// deepLinkValidator.js
import { ALLOWED_ROUTES, ALLOWED_SCHEMES, MAX_URL_LENGTH } from './deepLinkConfig';

export class DeepLinkValidationError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'DeepLinkValidationError';
    this.code = code;
  }
}

export function sanitizeString(input) {
  if (typeof input !== 'string') return '';
  // Remove null bytes, control characters, and trim
  return input
    .replace(/\0/g, '')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .trim();
}

export function parseDeepLinkUrl(url) {
  if (!url || typeof url !== 'string') {
    throw new DeepLinkValidationError('Invalid URL: empty or non-string', 'INVALID_URL');
  }

  const sanitizedUrl = sanitizeString(url);

  if (sanitizedUrl.length > MAX_URL_LENGTH) {
    throw new DeepLinkValidationError('URL exceeds maximum length', 'URL_TOO_LONG');
  }

  // Validate scheme
  const schemeMatch = sanitizedUrl.match(/^([a-zA-Z][a-zA-Z0-9+\-.]*):\/\//);
  if (!schemeMatch) {
    throw new DeepLinkValidationError('Invalid URL scheme', 'INVALID_SCHEME');
  }

  const scheme = schemeMatch[1].toLowerCase();
  if (!ALLOWED_SCHEMES.includes(scheme)) {
    throw new DeepLinkValidationError(`Scheme "${scheme}" is not allowed`, 'DISALLOWED_SCHEME');
  }

  // Parse the URL manually to avoid issues with non-standard schemes
  const withoutScheme = sanitizedUrl.slice(schemeMatch[0].length);
  const [pathAndQuery] = withoutScheme.split('#'); // strip fragment
  const [pathPart, queryString] = pathAndQuery.split('?');

  // Parse path segments
  const pathSegments = pathPart
    .split('/')
    .filter(segment => segment.length > 0)
    .map(segment => decodeURIComponent(segment))
    .map(segment => sanitizeString(segment));

  if (pathSegments.length === 0) {
    throw new DeepLinkValidationError('No route specified in URL', 'NO_ROUTE');
  }

  // Parse query parameters
  const queryParams = {};
  if (queryString) {
    const pairs = queryString.split('&');
    for (const pair of pairs) {
      const [rawKey, rawValue] = pair.split('=');
      if (rawKey) {
        const key = sanitizeString(decodeURIComponent(rawKey));
        const value = rawValue ? sanitizeString(decodeURIComponent(rawValue)) : '';
        // Prevent prototype pollution
        if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
          continue;
        }
        queryParams[key] = value;
      }
    }
  }

  return {
    scheme,
    pathSegments,
    queryParams,
  };
}

export function resolveRoute(pathSegments) {
  if (!pathSegments || pathSegments.length === 0) {
    return null;
  }

  const primaryRoute = pathSegments[0].toLowerCase();
  const routeConfig = ALLOWED_ROUTES[primaryRoute];

  if (!routeConfig) {
    return null; // Route not in allowlist
  }

  // Check for sub-routes
  if (pathSegments.length > 1 && routeConfig.subRoutes) {
    const subRoute = pathSegments[1].toLowerCase();
    const subRouteConfig = routeConfig.subRoutes[subRoute];

    if (subRouteConfig) {
      // Remaining segments after primary + sub route are treated as positional params
      const positionalParams = pathSegments.slice(2);
      return {
        screen: subRouteConfig.screen,
        paramValidators: subRouteConfig.paramValidators,
        requiresAuth: subRouteConfig.requiresAuth,
        positionalParams,
        routePath: `${primaryRoute}/${subRoute}`,
      };
    }
  }

  // Primary route with possible positional params (e.g., profile/123)
  const positionalParams = pathSegments.slice(1);
  return {
    screen: routeConfig.screen,
    paramValidators: routeConfig.paramValidators,
    requiresAuth: routeConfig.requiresAuth,
    positionalParams,
    routePath: primaryRoute,
  };
}

export function validateParams(params, validators) {
  const validatedParams = {};
  const errors = [];

  for (const [key, value] of Object.entries(params)) {
    if (validators[key]) {
      if (validators[key](value)) {
        validatedParams[key] = value;
      } else {
        errors.push(`Invalid value for parameter "${key}"`);
      }
    }
    // Parameters without validators are silently dropped (allowlist approach)
  }

  return { validatedParams, errors };
}

export function buildNavigationParams(parsedUrl, routeInfo) {
  // Merge positional params with query params based on route
  const rawParams = { ...parsedUrl.queryParams };

  // Map positional params based on route
  if (routeInfo.routePath === 'profile' && routeInfo.positionalParams.length > 0) {
    rawParams.id = routeInfo.positionalParams[0];
  } else if (routeInfo.routePath === 'invite' && routeInfo.positionalParams.length > 0) {
    rawParams.code = routeInfo.positionalParams[0];
  }

  // Validate all params
  const { validatedParams, errors } = validateParams(rawParams, routeInfo.paramValidators);

  if (errors.length > 0) {
    console.warn('Deep link parameter validation errors:', errors);
  }

  return validatedParams;
}


// deepLinkHandler.js
import { Linking, Platform } from 'react-native';
import { parseDeepLinkUrl, resolveRoute, buildNavigationParams, DeepLinkValidationError } from './deepLinkValidator';

class DeepLinkHandler {
  constructor() {
    this.navigationRef = null;
    this.authProvider = null;
    this.pendingDeepLink = null;
    this.isReady = false;
    this._linkingSubscription = null;
    this._rateLimitMap = new Map();
    this._rateLimitWindow = 2000; // 2 seconds
    this._rateLimitMax = 5; // max 5 deep links per window
  }

  initialize(navigationRef, authProvider) {
    this.navigationRef = navigationRef;
    this.authProvider = authProvider;
  }

  setReady(ready) {
    this.isReady = ready;
    if (ready && this.pendingDeepLink) {
      const pending = this.pendingDeepLink;
      this.pendingDeepLink = null;
      this.handleDeepLink(pending);
    }
  }

  _checkRateLimit() {
    const now = Date.now();
    // Clean old entries
    for (const [timestamp] of this._rateLimitMap) {
      if (now - timestamp > this._rateLimitWindow) {
        this._rateLimitMap.delete(timestamp);
      }
    }

    if (this._rateLimitMap.size >= this._rateLimitMax) {
      console.warn('Deep link rate limit exceeded');
      return false;
    }

    this._rateLimitMap.set(now, true);
    return true;
  }

  async handleDeepLink(url) {
    if (!url) return;

    // Rate limiting
    if (!this._checkRateLimit()) {
      return;
    }

    // If navigation isn't ready, queue the deep link
    if (!this.isReady || !this.navigationRef?.isReady()) {
      console.log('Navigation not ready, queuing deep link:', url);
      this.pendingDeepLink = url;
      return;
    }

    try {
      // Step 1: Parse and validate URL structure
      const parsedUrl = parseDeepLinkUrl(url);
      console.log('Parsed deep link:', JSON.stringify(parsedUrl));

      // Step 2: Resolve route against allowlist
      const routeInfo = resolveRoute(parsedUrl.pathSegments);
      if (!routeInfo) {
        console.warn(`Deep link route not allowed: ${parsedUrl.pathSegments.join('/')}`);
        this._navigateToFallback('Route not found');
        return;
      }

      // Step 3: Check authentication if required
      if (routeInfo.requiresAuth) {
        const isAuthenticated = await this._checkAuth();
        if (!isAuthenticated) {
          console.log('Authentication required for deep link, redirecting to login');
          this.pendingDeepLink = url; // Re-queue for after auth
          this._navigateToLogin(url);
          return;
        }
      }

      // Step 4: Validate and build navigation params
      const validatedParams = buildNavigationParams(parsedUrl, routeInfo);

      // Step 5: Navigate
      console.log(`Navigating to ${routeInfo.screen} with params:`, validatedParams);
      this._navigate(routeInfo.screen, validatedParams);

    } catch (error) {
      if (error instanceof DeepLinkValidationError) {
        console.warn(`Deep link validation failed [${error.code}]: ${error.message}`);
      } else {
        console.error('Unexpected error handling deep link:', error);
      }
      this._navigateToFallback('Invalid link');
    }
  }

  async _checkAuth() {
    if (!this.authProvider) {
      console.warn('No auth provider configured');
      return false;
    }

    try {
      return await this.authProvider.isAuthenticated();
    } catch (error) {
      console.error('Auth check failed:', error);
      return false;
    }
  }

  _navigate(screenName, params) {
    if (!this.navigationRef) {
      console.error('Navigation ref not available');
      return;
    }

    try {
      this.navigationRef.navigate(screenName, params);
    } catch (error) {
      console.error('Navigation failed:', error);
      this._navigateToFallback('Navigation error');
    }
  }

  _navigateToLogin(returnUrl) {
    this._navigate('LoginScreen', { returnUrl });
  }

  _navigateToFallback(reason) {
    try {
      if (this.navigationRef?.isReady()) {
        this.navigationRef.navigate('HomeScreen', { deepLinkError: reason });
      }
    } catch (error) {
      console.error('Fallback navigation failed:', error);
    }
  }

  startListening() {
    // Handle deep links when app is already open
    this._linkingSubscription = Linking.addEventListener('url', (event) => {
      console.log('Deep link received (foreground):', event.url);
      this.handleDeepLink(event.url);
    });

    // Handle deep link that opened the app
    Linking.getInitialURL()
      .then((url) => {
        if (url) {
          console.log('Deep link received (cold start):', url);
          this.handleDeepLink(url);
        }
      })
      .catch((error) => {
        console.error('Error getting initial URL:', error);
      });
  }

  stopListening() {
    if (this._linkingSubscription) {
      this._linkingSubscription.remove();
      this._linkingSubscription = null;
    }
  }

  // Process pending deep link after successful authentication
  processPendingAfterAuth() {
    if (this.pendingDeepLink) {
      const pending = this.pendingDeepLink;
      this.pendingDeepLink = null;
      this.handleDeepLink(pending);
    }
  }

  // For push notification deep links
  handlePushNotificationDeepLink(data) {
    if (!data || !data.deepLink) {
      console.warn('Push notification has no deep link data');
      return;
    }

    const url = sanitizePushDeepLink(data.deepLink);
    if (url) {
      this.handleDeepLink(url);
    }
  }
}

function sanitizePushDeepLink(deepLink) {
  if (typeof deepLink !== 'string') return null;

  // Ensure push notification deep links use our scheme
  if (!deepLink.startsWith('myapp://')) {
    console.warn('Push notification deep link has invalid scheme:', deepLink);
    return null;
  }

  return deepLink;
}

// Singleton instance
const deepLinkHandler = new DeepLinkHandler();
export default deepLinkHandler;


// authProvider.js
import AsyncStorage from '@react-native-async-storage/async-storage';

class AuthProvider {
  async isAuthenticated() {
    try {
      const token = await AsyncStorage.getItem('auth_token');
      if (!token) return false;

      // Optionally validate token expiry
      const tokenData = await AsyncStorage.getItem('auth_token_expiry');
      if (tokenData) {
        const expiry = parseInt(tokenData, 10);
        if (Date.now() > expiry) {
          await this.clearAuth();
          return false;
        }
      }

      return true;
    } catch (error) {
      console.error('Auth check error:', error);
      return false;
    }
  }

  async clearAuth() {
    await AsyncStorage.multiRemove(['auth_token', 'auth_token_expiry']);
  }
}

export default new AuthProvider();


